 * # Error Handling
 *
 * Validator errors are **fatal** - they cause the extraction to fail and bubble up
 * to the caller. Use validators for hard requirements that must be met.
 *
 * For non-fatal checks, use post-processors instead.
 *
 * # Thread Safety
 *
 * Validators must be thread-safe (`Send + Sync`).
 */
class Validator

data class TokenReductionConfig(
    val level: ReductionLevel,
    val languageHint: String?,
    val preserveMarkdown: Boolean,
    val preserveCode: Boolean,
    val semanticThreshold: Float,
    val enableParallel: Boolean,
    val useSimd: Boolean,
    val customStopwords: Map<String, List<String>>?,
    val preservePatterns: List<String>,
    val targetReduction: Float?,
    val enableSemanticClustering: Boolean,
)

/**
 * A PDF annotation extracted from a document page.
 */
data class PdfAnnotation(
    val annotationType: PdfAnnotationType,
    val content: String?,
    val pageNumber: Long,
    val boundingBox: String?,
)

/**
 * Comprehensive Djot document structure with semantic preservation.
 *
 * This type captures the full richness of Djot markup, including:
 * - Block-level structures (headings, lists, blockquotes, code blocks, etc.)
 * - Inline formatting (emphasis, strong, highlight, subscript, superscript, etc.)
 * - Attributes (classes, IDs, key-value pairs)
 * - Links, images, footnotes
 * - Math expressions (inline and display)
 * - Tables with full structure
 *
 * Available when the `djot` feature is enabled.
 */
data class DjotContent(
    val plainText: String,
    val blocks: List<FormattedBlock>,
    val metadata: Metadata,
    val tables: List<Table>,
    val images: List<DjotImage>,
    val links: List<DjotLink>,
    val footnotes: List<Footnote>,
    val attributes: List<String>,
)

/**
 * Block-level element in a Djot document.
 *
 * Represents structural elements like headings, paragraphs, lists, code blocks, etc.
 */
data class FormattedBlock(
    val blockType: BlockType,
    val level: Long?,
    val inlineContent: List<InlineElement>,
    val attributes: String?,
    val language: String?,
    val code: String?,
    val children: List<FormattedBlock>,
)

/**
 * Inline element within a block.
 *
 * Represents text with formatting, links, images, etc.
 */
data class InlineElement(
    val elementType: InlineType,
    val content: String,
    val attributes: String?,
    val metadata: Map<String, String>?,
)

/**
 * Image element in Djot.
 */
data class DjotImage(
    val src: String,
    val alt: String,
    val title: String?,
    val attributes: String?,
)

/**
 * Link element in Djot.
 */
data class DjotLink(
    val url: String,
    val text: String,
    val title: String?,
    val attributes: String?,
)

/**
 * Footnote in Djot.
 */
data class Footnote(
    val label: String,
    val content: List<FormattedBlock>,
)

/**
 * Top-level structured document representation.
 *
 * A flat array of nodes with index-based parent/child references forming a tree.
 * Root-level nodes have `parent: None`. Use `body_roots()` and `furniture_roots()`
 * to iterate over top-level content by layer.
 *
 * # Validation
 *
 * Call `validate()` after construction to verify all node indices are in bounds
 * and parent-child relationships are bidirectionally consistent.
 */
data class DocumentStructure(
    val nodes: List<DocumentNode>,
    val sourceFormat: String?,
    val relationships: List<DocumentRelationship>,
    val nodeTypes: List<String>,
)

/**
 * A resolved relationship between two nodes in the document tree.
 */
data class DocumentRelationship(
    val source: Int,
    val target: Int,
    val kind: RelationshipKind,
)

/**
 * A single node in the document tree.
 *
 * Each node has deterministic `id`, typed `content`, optional `parent`/`children`
 * for tree structure, and metadata like page number, bounding box, and content layer.
 */
data class DocumentNode(
    val id: String,
    val content: NodeContent,
    val parent: Int?,
    val children: List<Int>,
    val contentLayer: ContentLayer,
    val page: Int?,
    val pageEnd: Int?,
    val bbox: String?,
    val annotations: List<TextAnnotation>,
    val attributes: Map<String, String>?,
)

/**
 * Structured table grid with cell-level metadata.
 *
 * Stores row/column dimensions and a flat list of cells with position info.
 */
data class TableGrid(
    val rows: Int,
    val cols: Int,
    val cells: List<GridCell>,
)

/**
 * Individual grid cell with position and span metadata.
 */
data class GridCell(
    val content: String,
    val row: Int,
    val col: Int,
    val rowSpan: Int,
    val colSpan: Int,
    val isHeader: Boolean,
    val bbox: String?,
)

/**
 * Inline text annotation — byte-range based formatting and links.
 *
 * Annotations reference byte offsets into the node's text content,
 * enabling precise identification of formatted regions.
 */
data class TextAnnotation(
    val start: Int,
    val end: Int,
    val kind: AnnotationKind,
)

/**
 * General extraction result used by the core extraction API.
 *
 * This is the main result type returned by all extraction functions.
 */
data class ExtractionResult(
    val content: String,
    val mimeType: String,
    val metadata: Metadata,
    val extractionMethod: ExtractionMethod?,
    val tables: List<Table>,
    val detectedLanguages: List<String>?,
    val chunks: List<Chunk>?,
    val images: List<ExtractedImage>?,
    val pages: List<PageContent>?,
    val elements: List<Element>?,
    val djotContent: DjotContent?,
    val ocrElements: List<OcrElement>?,
    val document: DocumentStructure?,
    val extractedKeywords: List<Keyword>?,
    val qualityScore: Double?,
    val processingWarnings: List<ProcessingWarning>,
    val annotations: List<PdfAnnotation>?,
    val children: List<ArchiveEntry>?,
    val uris: List<Uri>?,
    val structuredOutput: String?,
    val codeIntelligence: String?,
    val llmUsage: List<LlmUsage>?,
    val formattedContent: String?,
    val ocrInternalDocument: String?,
)

/**
 * A single file extracted from an archive.
 *
 * When archives (ZIP, TAR, 7Z, GZIP) are extracted with recursive extraction
 * enabled, each processable file produces its own full `ExtractionResult`.
 */
data class ArchiveEntry(
    val path: String,
    val mimeType: String,
    val result: ExtractionResult,
)

/**
 * A non-fatal warning from a processing pipeline stage.
 *
 * Captures errors from optional features that don't prevent extraction
 * but may indicate degraded results.
 */
data class ProcessingWarning(
    val source: String,
    val message: String,
)

/**
 * Token usage and cost data for a single LLM call made during extraction.
 *
 * Populated when VLM OCR, structured extraction, or LLM-based embeddings
 * are used. Multiple entries may be present when multiple LLM calls occur
 * within one extraction (e.g. VLM OCR + structured extraction).
 */
data class LlmUsage(
    val model: String,
    val source: String,
    val inputTokens: Long?,
    val outputTokens: Long?,
    val totalTokens: Long?,
    val estimatedCost: Double?,
    val finishReason: String?,
)

/**
 * A text chunk with optional embedding and metadata.
 *
 * Chunks are created when chunking is enabled in `ExtractionConfig`. Each chunk
 * contains the text content, optional embedding vector (if embedding generation
 * is configured), and metadata about its position in the document.
 */
data class Chunk(
    val content: String,
    val chunkType: ChunkType,
    val embedding: List<Float>?,
    val metadata: ChunkMetadata,
)

/**
 * Heading context for a chunk within a Markdown document.
 *
 * Contains the heading hierarchy from document root to this chunk's section.
 */
data class HeadingContext(
    val headings: List<HeadingLevel>,
)

/**
 * A single heading in the hierarchy.
 */
data class HeadingLevel(
    val level: Byte,
    val text: String,
)

/**
 * Metadata about a chunk's position in the original document.
 */
data class ChunkMetadata(
    val byteStart: Long,
    val byteEnd: Long,
    val tokenCount: Long?,
    val chunkIndex: Long,
    val totalChunks: Long,
    val firstPage: Long?,
    val lastPage: Long?,
    val headingContext: HeadingContext?,
)

/**
 * Extracted image from a document.
 *
 * Contains raw image data, metadata, and optional nested OCR results.
 * Raw bytes allow cross-language compatibility - users can convert to
 * PIL.Image (Python), Sharp (Node.js), or other formats as needed.
 */
data class ExtractedImage(
    val data: ByteArray,
    val format: String,
    val imageIndex: Long,
    val pageNumber: Long?,
    val width: Int?,
    val height: Int?,
    val colorspace: String?,
    val bitsPerComponent: Int?,
    val isMask: Boolean,
    val description: String?,
    val ocrResult: ExtractionResult?,
    val boundingBox: String?,
    val sourcePath: String?,
    val imageKind: ImageKind?,
    val kindConfidence: Float?,
    val clusterId: Int?,
)

/**
 * Metadata for a semantic element.
 */
data class ElementMetadata(
    val pageNumber: Long?,
    val filename: String?,
    val coordinates: String?,
    val elementIndex: Long?,
    val additional: Map<String, String>,
)

/**
 * Semantic element extracted from document.
 *
 * Represents a logical unit of content with semantic classification,
 * unique identifier, and metadata for tracking origin and position.
 */
data class Element(
    val elementId: String,
    val elementType: ElementType,
    val text: String,
    val metadata: ElementMetadata,
)

/**
 * Excel workbook representation.
 *
 * Contains all sheets from an Excel file (.xlsx, .xls, etc.) with
 * extracted content and metadata.
 */
data class ExcelWorkbook(
    val sheets: List<ExcelSheet>,
    val metadata: Map<String, String>,
)

/**
 * Single Excel worksheet.
 *
 * Represents one sheet from an Excel workbook with its content
 * converted to Markdown format and dimensional statistics.
 */
data class ExcelSheet(
    val name: String,
    val markdown: String,
    val rowCount: Long,
    val colCount: Long,
    val cellCount: Long,
    val tableCells: List<List<String>>?,
)

/**
 * XML extraction result.
 *
 * Contains extracted text content from XML files along with
 * structural statistics about the XML document.
 */
data class XmlExtractionResult(
    val content: String,
    val elementCount: Long,
    val uniqueElements: List<String>,
)

/**
 * Plain text and Markdown extraction result.
 *
 * Contains the extracted text along with statistics and,
 * for Markdown files, structural elements like headers and links.
 */
data class TextExtractionResult(
    val content: String,
    val lineCount: Long,
    val wordCount: Long,
    val characterCount: Long,
    val headers: List<String>?,
    val links: List<String>?,
    val codeBlocks: List<String>?,
)

/**
 * PowerPoint (PPTX) extraction result.
 *
 * Contains extracted slide content, metadata, and embedded images/tables.
 */
data class PptxExtractionResult(
    val content: String,
    val metadata: PptxMetadata,
    val slideCount: Long,
    val imageCount: Long,
    val tableCount: Long,
    val images: List<ExtractedImage>,
    val pageStructure: PageStructure?,
    val pageContents: List<PageContent>?,
    val document: DocumentStructure?,
    val hyperlinks: List<String>,
    val officeMetadata: Map<String, String>,
)

/**
 * Email extraction result.
 *
 * Complete representation of an extracted email message (.eml or .msg)
 * including headers, body content, and attachments.
 */
data class EmailExtractionResult(
    val subject: String?,
    val fromEmail: String?,
    val toEmails: List<String>,
    val ccEmails: List<String>,
    val bccEmails: List<String>,
    val date: String?,
    val messageId: String?,
    val plainText: String?,
    val htmlContent: String?,
    val content: String,
    val attachments: List<EmailAttachment>,
    val metadata: Map<String, String>,
)

/**
 * Email attachment representation.
 *
 * Contains metadata and optionally the content of an email attachment.
 */
data class EmailAttachment(
    val name: String?,
    val filename: String?,
    val mimeType: String?,
    val size: Long?,
    val isImage: Boolean,
    val data: ByteArray?,
)

/**
 * OCR extraction result.
 *
 * Result of performing OCR on an image or scanned document,
 * including recognized text and detected tables.
 */
data class OcrExtractionResult(
    val content: String,
    val mimeType: String,
    val metadata: Map<String, String>,
    val tables: List<OcrTable>,
    val ocrElements: List<OcrElement>?,
    val internalDocument: String?,
)

/**
 * Table detected via OCR.
 *
 * Represents a table structure recognized during OCR processing.
 */
data class OcrTable(
    val cells: List<List<String>>,
    val markdown: String,
    val pageNumber: Long,
    val boundingBox: OcrTableBoundingBox?,
)

/**
 * Bounding box for an OCR-detected table in pixel coordinates.
 */
data class OcrTableBoundingBox(
    val left: Int,
    val top: Int,
    val right: Int,
    val bottom: Int,
)

/**
 * Image preprocessing configuration for OCR.
 *
 * These settings control how images are preprocessed before OCR to improve
 * text recognition quality. Different preprocessing strategies work better
 * for different document types.
 */
data class ImagePreprocessingConfig(
    val targetDpi: Int,
    val autoRotate: Boolean,
    val deskew: Boolean,
    val denoise: Boolean,
    val contrastEnhance: Boolean,
    val binarizationMethod: String,
    val invertColors: Boolean,
)

/**
 * Tesseract OCR configuration.
 *
 * Provides fine-grained control over Tesseract OCR engine parameters.
 * Most users can use the defaults, but these settings allow optimization
 * for specific document types (invoices, handwriting, etc.).
 */
data class TesseractConfig(
    val language: String,
    val psm: Int,
    val outputFormat: String,
    val oem: Int,
    val minConfidence: Double,
    val preprocessing: ImagePreprocessingConfig?,
    val enableTableDetection: Boolean,
    val tableMinConfidence: Double,
    val tableColumnThreshold: Int,
    val tableRowThresholdRatio: Double,
    val useCache: Boolean,
    val classifyUsePreAdaptedTemplates: Boolean,
    val languageModelNgramOn: Boolean,
    val tesseditDontBlkrejGoodWds: Boolean,
    val tesseditDontRowrejGoodWds: Boolean,
    val tesseditEnableDictCorrection: Boolean,
    val tesseditCharWhitelist: String,
    val tesseditCharBlacklist: String,
    val tesseditUsePrimaryParamsModel: Boolean,
    val textordSpaceSizeIsVariable: Boolean,
    val thresholdingMethod: Boolean,
)

/**
 * Image preprocessing metadata.
 *
 * Tracks the transformations applied to an image during OCR preprocessing,
 * including DPI normalization, resizing, and resampling.
 */
data class ImagePreprocessingMetadata(
    val originalDimensions: List<Long>,
    val originalDpi: List<Double>,
    val targetDpi: Int,
    val scaleFactor: Double,
    val autoAdjusted: Boolean,
    val finalDpi: Int,
    val newDimensions: List<Long>?,
    val resampleMethod: String,
    val dimensionClamped: Boolean,
    val calculatedDpi: Int?,
    val skippedResize: Boolean,
    val resizeError: String?,
)

/**
 * Extraction result metadata.
 *
 * Contains common fields applicable to all formats, format-specific metadata
 * via a discriminated union, and additional custom fields from postprocessors.
 */
data class Metadata(
    val title: String?,
    val subject: String?,
    val authors: List<String>?,
    val keywords: List<String>?,
    val language: String?,
    val createdAt: String?,
    val modifiedAt: String?,
    val createdBy: String?,
    val modifiedBy: String?,
    val pages: PageStructure?,
    val format: FormatMetadata?,
    val imagePreprocessing: ImagePreprocessingMetadata?,
    val jsonSchema: String?,
    val error: ErrorMetadata?,
    val extractionDurationMs: Long?,
    val category: String?,
    val tags: List<String>?,
    val documentVersion: String?,
    val abstractText: String?,
    val outputFormat: String?,
    val ocrUsed: Boolean,
    val additional: Map<String, String>,
)

/**
 * Excel/spreadsheet format metadata.
 *
 * Identifies the document as a spreadsheet source via the `FormatMetadata.Excel`
 * discriminant. Sheet count and sheet names are stored inside this struct.
 */
data class ExcelMetadata(
    val sheetCount: Long?,
    val sheetNames: List<String>?,
)

/**
 * Email metadata extracted from .eml and .msg files.
 *
 * Includes sender/recipient information, message ID, and attachment list.
 */
data class EmailMetadata(
    val fromEmail: String?,
    val fromName: String?,
    val toEmails: List<String>,
    val ccEmails: List<String>,
    val bccEmails: List<String>,
    val messageId: String?,
    val attachments: List<String>,
)

/**
 * Archive (ZIP/TAR/7Z) metadata.
 *
 * Extracted from compressed archive files containing file lists and size information.
 */
data class ArchiveMetadata(
    val format: String,
    val fileCount: Long,
    val fileList: List<String>,
    val totalSize: Long,
    val compressedSize: Long?,
)

/**
 * Image metadata extracted from image files.
 *
 * Includes dimensions, format, and EXIF data.
 */
data class ImageMetadata(
    val width: Int,
    val height: Int,
    val format: String,
    val exif: Map<String, String>,
)

/**
 * XML metadata extracted during XML parsing.
 *
 * Provides statistics about XML document structure.
 */
data class XmlMetadata(
    val elementCount: Long,
    val uniqueElements: List<String>,
)

/**
 * Text/Markdown metadata.
 *
 * Extracted from plain text and Markdown files. Includes word counts and,
 * for Markdown, structural elements like headers and links.
 */
data class TextMetadata(
    val lineCount: Long,
    val wordCount: Long,
    val characterCount: Long,
    val headers: List<String>?,
    val links: List<String>?,
    val codeBlocks: List<String>?,
)

/**
 * Header/heading element metadata.
 */
data class HeaderMetadata(
    val level: Byte,
    val text: String,
    val id: String?,
    val depth: Long,
    val htmlOffset: Long,
)

/**
 * Link element metadata.
 */
data class LinkMetadata(
    val href: String,
    val text: String,
    val title: String?,
    val linkType: LinkType,
    val rel: List<String>,
    val attributes: List<String>,
)

/**
 * Image element metadata.
 */
data class ImageMetadataType(
    val src: String,
    val alt: String?,
    val title: String?,
    val dimensions: List<Int>?,
    val imageType: ImageType,
    val attributes: List<String>,
)

/**
 * Structured data (Schema.org, microdata, RDFa) block.
 */
data class StructuredData(
    val dataType: StructuredDataType,
    val rawJson: String,
    val schemaType: String?,
)

/**
 * HTML metadata extracted from HTML documents.
 *
 * Includes document-level metadata, Open Graph data, Twitter Card metadata,
 * and extracted structural elements (headers, links, images, structured data).
 */
data class HtmlMetadata(
    val title: String?,
    val description: String?,
    val keywords: List<String>,
    val author: String?,
    val canonicalUrl: String?,
    val baseHref: String?,
    val language: String?,
    val textDirection: TextDirection?,
    val openGraph: Map<String, String>,
    val twitterCard: Map<String, String>,
    val metaTags: Map<String, String>,
    val headers: List<HeaderMetadata>,
    val links: List<LinkMetadata>,
    val images: List<ImageMetadataType>,
    val structuredData: List<StructuredData>,
)

/**
 * OCR processing metadata.
 *
 * Captures information about OCR processing configuration and results.
 */
data class OcrMetadata(
    val language: String,
    val psm: Int,
    val outputFormat: String,
    val tableCount: Long,
    val tableRows: Long?,
    val tableCols: Long?,
)

/**
 * Error metadata (for batch operations).
 */
data class ErrorMetadata(
    val errorType: String,
    val message: String,
)

/**
 * PowerPoint presentation metadata.
 *
 * Extracted from PPTX files containing slide counts and presentation details.
 */
data class PptxMetadata(
    val slideCount: Long,
    val slideNames: List<String>,
    val imageCount: Long?,
    val tableCount: Long?,
)

/**
 * Word document metadata.
 *
 * Extracted from DOCX files using shared Office Open XML metadata extraction.
 * Integrates with `office_metadata` module for core/app/custom properties.
 */
data class DocxMetadata(
    val coreProperties: CoreProperties?,
    val appProperties: DocxAppProperties?,
    val customProperties: Map<String, String>?,
)

/**
 * CSV/TSV file metadata.
 */
data class CsvMetadata(
    val rowCount: Long,
    val columnCount: Long,
    val delimiter: String?,
    val hasHeader: Boolean,
    val columnTypes: List<String>?,
)

/**
 * BibTeX bibliography metadata.
 */
data class BibtexMetadata(
    val entryCount: Long,
    val citationKeys: List<String>,
    val authors: List<String>,
    val yearRange: YearRange?,
    val entryTypes: Map<String, Long>?,
)

/**
 * Citation file metadata (RIS, PubMed, EndNote).
 */
data class CitationMetadata(
    val citationCount: Long,
    val format: String?,
    val authors: List<String>,
    val yearRange: YearRange?,
    val dois: List<String>,
    val keywords: List<String>,
)

/**
 * Year range for bibliographic metadata.
 */
data class YearRange(
    val min: Int?,
    val max: Int?,
