)

/**
 * FictionBook (FB2) metadata.
 */
data class FictionBookMetadata(
    val genres: List<String>,
    val sequences: List<String>,
    val annotation: String?,
)

/**
 * dBASE (DBF) file metadata.
 */
data class DbfMetadata(
