    val fieldCount: Long,
    val fields: List<DbfFieldInfo>,
)

/**
 * dBASE field information.
 */
data class DbfFieldInfo(
    val name: String,
    val fieldType: String,
)

/**
 * JATS (Journal Article Tag Suite) metadata.
 */
data class JatsMetadata(
    val copyright: String?,
    val license: String?,
