)

/**
 * Configuration for OCR element extraction.
 *
 * Controls how OCR elements are extracted and filtered.
 */
data class OcrElementConfig(
    val includeElements: Boolean,
    val minLevel: OcrElementLevel,
    val minConfidence: Double,
    val buildHierarchy: Boolean,
)

/**
 * Unified page structure for documents.
 *
 * Supports different page types (PDF pages, PPTX slides, Excel sheets)
 * with character offset boundaries for chunk-to-page mapping.
 */
data class PageStructure(
    val totalCount: Long,
    val unitType: PageUnitType,
    val boundaries: List<PageBoundary>?,
    val pages: List<PageInfo>?,
)

/**
 * Byte offset boundary for a page.
 *
 * Tracks where a specific page's content starts and ends in the main content string,
 * enabling mapping from byte positions to page numbers. Offsets are guaranteed to be
 * at valid UTF-8 character boundaries when using standard String methods (push_str, push, etc.).
 */
data class PageBoundary(
    val byteStart: Long,
    val byteEnd: Long,
    val pageNumber: Long,
)

/**
 * Metadata for individual page/slide/sheet.
 *
 * Captures per-page information including dimensions, content counts,
 * and visibility state (for presentations).
 */
data class PageInfo(
    val number: Long,
    val title: String?,
    val dimensions: List<Double>?,
    val imageCount: Long?,
    val tableCount: Long?,
    val hidden: Boolean?,
    val isBlank: Boolean?,
    val hasVectorGraphics: Boolean,
)

/**
 * Content for a single page/slide.
 *
 * When page extraction is enabled, documents are split into per-page content
 * with associated tables and images mapped to each page.
 *
 * # Performance
 *
 * Uses Arc-wrapped tables and images for memory efficiency:
 * - `Vec<Arc<Table>>` enables zero-copy sharing of table data
 * - `Vec<Arc<ExtractedImage>>` enables zero-copy sharing of image data
 * - Maintains exact JSON compatibility via custom Serialize/Deserialize
 *
 * This reduces memory overhead for documents with shared tables/images
 * by avoiding redundant copies during serialization.
 */
data class PageContent(
    val pageNumber: Long,
    val content: String,
    val tables: List<Table>,
    val images: List<ExtractedImage>,
    val hierarchy: PageHierarchy?,
    val isBlank: Boolean?,
    val layoutRegions: List<LayoutRegion>?,
)

/**
 * A detected layout region on a page.
 *
 * When layout detection is enabled, each page may have layout regions
 * identifying different content types (text, pictures, tables, etc.)
 * with confidence scores and spatial positions.
 */
data class LayoutRegion(
    val className: String,
    val confidence: Double,
    val boundingBox: String,
    val areaFraction: Double,
)

/**
 * Page hierarchy structure containing heading levels and block information.
 *
